module priority_encoder_8to3(
    input       [7:0]     unavailable_data,

    output reg            valid,
    output reg  [2:0]     encoded
);

// Priority encoder implementation
always @(*) begin
    if (unavailable_data[7])
        encoded = 3'd7;
    else if (unavailable_data[6])
        encoded = 3'd6;
    else if (unavailable_data[5])
        encoded = 3'd5;
    else if (unavailable_data[4])
        encoded = 3'd4;
    else if (unavailable_data[3])
        encoded = 3'd3;
    else if (unavailable_data[2])
        encoded = 3'd2;
    else if (unavailable_data[1])
        encoded = 3'd1;
    else if (unavailable_data[0])
        encoded = 3'd0;
    else
        encoded = 3'd0;

    valid = (unavailable_data != 8'd0);
end

endmodule
